import streamlit as stimport pandas as pd# --- Naslov ---st.markdown("<h1 style='text-align: center;'>⚽ FIFA World Cup 2026 ⚽</h1>", unsafe_allow_html=True)# Sidebarpage = st.sidebar.selectbox("Izaberi stranicu:", ["Poredak", "Prvo kolo"])if page == "Poredak":    df = pd.read_csv("players.csv", header=None, encoding='utf-8-sig')    df.columns = ["Igrači", "Bodovi"]    df = df.sort_values("Bodovi", ascending=False).reset_index(drop=True)    df.insert(2, "Pozicija", range(1, len(df)+1))    st.markdown("<h3 style='text-align: center;'>🏆 Poredak</h3>", unsafe_allow_html=True)    # --- Centriraj i prikaži statičnu tablicu ---    df_styled = df.style.set_properties(**{'text-align': 'center'})    st.table(df_styled)elif page == "Prvo kolo":    df_round = pd.read_csv("round1.csv", header=None, encoding='utf-8-sig')    df_round.columns = ["Igrači", "CRO-ESP", "ENG-GER", "BEL-HUN", "ITA-BOS"]    st.markdown("<h3 style='text-align: center;'>📊 Tipovi za prvo kolo</h3>", unsafe_allow_html=True)    df_round_styled = df_round.style.set_properties(**{'text-align': 'center'})    st.table(df_round_styled)